import{_ as a,o as e,c as r,a2 as d}from"./chunks/framework.wfnuidXa.js";const u=JSON.parse('{"title":"日常使用","description":"","frontmatter":{},"headers":[],"relativePath":"guide/usage.md","filePath":"guide/usage.md","lastUpdated":1780989355000}'),i={name:"guide/usage.md"};function l(o,t,n,s,h,c){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="日常使用" tabindex="-1">日常使用 <a class="header-anchor" href="#日常使用" aria-label="Permalink to &quot;日常使用&quot;">​</a></h1><p>LiteWaf 的日常操作围绕“创建资源、调整防护、发布配置、验证网关效果”展开。控制面保存配置，Gateway 只执行已发布版本。</p><h2 id="操作流程" tabindex="-1">操作流程 <a class="header-anchor" href="#操作流程" aria-label="Permalink to &quot;操作流程&quot;">​</a></h2><ol><li>创建站点，填写域名、监听端口、协议和源站。</li><li>配置规则、策略、IP 黑白名单、访问控制、限流和防护模块。</li><li>使用发布预览检查将要下发到 Gateway 的配置。</li><li>发布配置。</li><li>通过网关访问业务域名或端口，查看访问日志、攻击日志、统计报表和发布记录。</li></ol><h2 id="发布生命周期" tabindex="-1">发布生命周期 <a class="header-anchor" href="#发布生命周期" aria-label="Permalink to &quot;发布生命周期&quot;">​</a></h2><p>以下变更必须发布后才会进入 Gateway：</p><ul><li>站点、监听端口、证书和源站。</li><li>规则、规则集、策略和评分阈值。</li><li>IP 黑名单、IP 白名单、访问控制和限流。</li><li>CC 防护、Bot 防护、动态防护、上传防护和高级规则配置。</li></ul><p>如果后台保存成功但网关行为没有变化，优先检查发布记录、当前生效版本和 Gateway 日志。</p><h2 id="验证方式" tabindex="-1">验证方式 <a class="header-anchor" href="#验证方式" aria-label="Permalink to &quot;验证方式&quot;">​</a></h2><table tabindex="0"><thead><tr><th>目标</th><th>建议检查</th></tr></thead><tbody><tr><td>正常代理</td><td>通过 Gateway 访问业务 URL，确认返回源站响应</td></tr><tr><td>WAF 拦截</td><td>构造命中规则的请求，确认返回拦截响应</td></tr><tr><td>日志回流</td><td>查看访问日志、WAF 事件和统计报表</td></tr><tr><td>发布状态</td><td>查看发布记录、版本号和 Gateway 配置刷新状态</td></tr></tbody></table><p>完整操作细节见 <a href="https://github.com/newz-max/litewaf-api/blob/master/doc/%E4%BD%BF%E7%94%A8%E8%AF%B4%E6%98%8E.md" target="_blank" rel="noreferrer"><code>litewaf-api/doc/使用说明.md</code></a>。</p>',11)])])}const _=a(i,[["render",l]]);export{u as __pageData,_ as default};
